import type { FeatureCollection, MultiPolygon, Polygon } from 'geojson';

// ---------------------------------------------------------------------------
// Faction Types & Assignments
// ---------------------------------------------------------------------------

export type FactionId =
  | 'iran'
  | 'us'
  | 'turkic'
  | 'contested_iran_us'
  | 'contested_iran_china_us'
  | 'neutral';

/**
 * Maps Natural Earth ADM0_A3 codes to faction alignment.
 * Uses ADM0_A3 (always populated) instead of ISO_A3 (some countries have -99).
 * Countries within MAX_BOUNDS not listed here default to 'neutral'.
 */
export const FACTION_MAP: Record<string, FactionId> = {
  // Iran Axis
  IRN: 'iran',
  SYR: 'iran',
  YEM: 'iran',

  // US-Aligned (Egypt placed US-aligned per Camp David Accords / US military aid)
  ISR: 'us',
  SAU: 'us',
  ARE: 'us',
  BHR: 'us', // Not in 110m (too small) but kept for completeness
  JOR: 'us',
  KWT: 'us',
  QAT: 'us',
  EGY: 'us',

  // Turkic Bloc
  TUR: 'turkic',
  AZE: 'turkic',
  TKM: 'turkic',

  // Contested (Iran + US influence)
  IRQ: 'contested_iran_us',
  LBN: 'contested_iran_us',

  // Contested (Iran/China + US influence)
  PAK: 'contested_iran_china_us',

  // Explicitly neutral
  OMN: 'neutral',
  AFG: 'neutral',
};

/** RGB color tuples for each faction */
export const FACTION_COLORS: Record<FactionId, [number, number, number]> = {
  iran: [239, 68, 68],
  us: [59, 130, 246],
  turkic: [245, 158, 11],
  contested_iran_us: [156, 163, 175], // display uses dual pattern
  contested_iran_china_us: [156, 163, 175], // display uses dual pattern
  neutral: [156, 163, 175],
};

/** Color pairs for dual-stripe contested patterns */
export const CONTESTED_COLOR_PAIRS: Record<string, [[number, number, number], [number, number, number]]> = {
  contested_iran_us: [[239, 68, 68], [59, 130, 246]],
  contested_iran_china_us: [[239, 68, 68], [59, 130, 246]],
};

/** Faction definitions for iterating fill layers */
